import "dotenv/config";

function safeErr(err) {
  return err?.response?.data?.error?.message ||
    err?.response?.data?.message ||
    err?.message ||
    String(err);
}

process.on("unhandledRejection", (err) => {
  console.error("[fatal] unhandledRejection", { error: safeErr(err) });
  process.exit(1);
});

process.on("uncaughtException", (err) => {
  console.error("[fatal] uncaughtException", { error: safeErr(err) });
  process.exit(1);
});

async function boot() {
  console.log("[boot] start");

  try {
    const [{ loadConfig }, { connectMongo, ensureIndexes, closeMongo }, { startBot }, logger] = await Promise.all([
      import("./lib/config.js"),
      import("./db/mongo.js"),
      import("./bot.js"),
      import("./lib/logger.js"),
    ]);

    const cfg = loadConfig();

    logger.info("config loaded", {
      platform: "x",
      COOKMYBOTS_X_ENDPOINT_set: Boolean(cfg.COOKMYBOTS_X_ENDPOINT),
      COOKMYBOTS_X_KEY_set: Boolean(cfg.COOKMYBOTS_X_KEY),
      MONGODB_URI_set: Boolean(cfg.MONGODB_URI),
      monitorKeywordsConfigured: cfg.monitorKeywords.length > 0,
      monitorAccountsConfigured: cfg.monitorAccounts.length > 0,
      dryRun: cfg.dryRun,
      postReports: cfg.postReports,
      postAlerts: cfg.postAlerts,
    });

    const missing = [];
    if (!cfg.COOKMYBOTS_X_ENDPOINT) missing.push("COOKMYBOTS_X_ENDPOINT");
    if (!cfg.COOKMYBOTS_X_KEY) missing.push("COOKMYBOTS_X_KEY");
    if (!cfg.MONGODB_URI) missing.push("MONGODB_URI");

    if (missing.length) {
      console.error("[boot] missing required environment variables", { missing });
      console.error("[boot] set the missing variables in your service configuration and restart.");
      process.exit(1);
    }

    const db = await connectMongo(cfg.MONGODB_URI);
    await ensureIndexes(db);

    const shutdown = async (signal) => {
      logger.info("shutdown requested", { signal });
      await closeMongo();
      process.exit(0);
    };

    process.once("SIGINT", () => void shutdown("SIGINT"));
    process.once("SIGTERM", () => void shutdown("SIGTERM"));

    await startBot({ cfg, db });
  } catch (err) {
    console.error("[boot] failed", { error: safeErr(err) });
    console.error("[boot] check package installation, environment variables, MongoDB access, and relative imports.");
    process.exit(1);
  }
}

await boot();

config.js.content:
function parseList(value) {
  return String(value || "")
    .split(",")
    .map((item) => item.trim())
    .filter(Boolean);
}

function parseBool(value, fallback = false) {
  const raw = String(value ?? "").trim().toLowerCase();
  if (!raw) return fallback;
  return ["1", "true", "yes", "on"].includes(raw);
}

function numberInRange(value, fallback, min, max) {
  const n = Number(value ?? fallback);
  if (!Number.isFinite(n)) return fallback;
  return Math.max(min, Math.min(max, n));
}

function normalizeAccounts(accounts) {
  return accounts
    .map((account) => account.replace(/^@+/, "").trim())
    .filter(Boolean);
}

export function loadConfig() {
  const monitorKeywords = parseList(process.env.X_MONITOR_KEYWORDS || "");
  const monitorAccounts = normalizeAccounts(parseList(process.env.X_MONITOR_ACCOUNTS || ""));

  return {
    COOKMYBOTS_X_ENDPOINT: process.env.COOKMYBOTS_X_ENDPOINT || "",
    COOKMYBOTS_X_KEY: process.env.COOKMYBOTS_X_KEY || "",
    MONGODB_URI: process.env.MONGODB_URI || "",

    monitorKeywords,
    monitorAccounts,

    pollIntervalSeconds: numberInRange(process.env.X_POLL_INTERVAL_SECONDS, 300, 300, 24 * 60 * 60),
    reportIntervalHours: numberInRange(process.env.X_REPORT_INTERVAL_HOURS, 6, 1, 168),
    spikeWindowMinutes: numberInRange(process.env.X_SPIKE_WINDOW_MINUTES, 60, 5, 24 * 60),
    spikeVolumeMultiplier: numberInRange(process.env.X_SPIKE_VOLUME_MULTIPLIER, 3, 1, 100),
    spikeNegativeShareThreshold: numberInRange(process.env.X_SPIKE_NEGATIVE_SHARE_THRESHOLD, 0.5, 0.01, 1),

    postReports: parseBool(process.env.X_POST_REPORTS || "false", false),
    postAlerts: parseBool(process.env.X_POST_ALERTS || "false", false),
    dryRun: parseBool(process.env.X_DRY_RUN || "true", true),
  };
}

logger.js.content:
export function safeErr(err) {
  return err?.response?.data?.error?.message ||
    err?.response?.data?.message ||
    err?.message ||
    String(err);
}

function write(level, message, meta = {}) {
  const row = {
    level,
    message,
    ts: new Date().toISOString(),
    ...meta,
  };

  const line = JSON.stringify(row);
  if (level === "error") console.error(line);
  else if (level === "warn") console.warn(line);
  else console.log(line);
}

export function info(message, meta = {}) {
  write("info", message, meta);
}

export function warn(message, meta = {}) {
  write("warn", message, meta);
}

export function error(message, meta = {}) {
  write("error", message, meta);
}

let lastMemoryLogAt = 0;

export function memoryLog() {
  const now = Date.now();
  if (now - lastMemoryLogAt < 60_000) return;
  lastMemoryLogAt = now;

  const m = process.memoryUsage();
  info("memory", {
    rssMB: Math.round(m.rss / 1e6),
    heapUsedMB: Math.round(m.heapUsed / 1e6),
  });
}

xProxy.js.content:
import { info, warn, error, safeErr } from "./logger.js";

function trimSlash(value) {
  let out = String(value || "");
  while (out.endsWith("/")) out = out.slice(0, -1);
  return out;
}

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

async function readResponse(response) {
  const text = await response.text().catch(() => "");
  let json = null;
  try {
    json = text ? JSON.parse(text) : null;
  } catch {
    json = null;
  }
  return { text, json };
}

function headerValue(headers, key) {
  return headers?.[key] || headers?.[key.toLowerCase()] || headers?.[key.toUpperCase()] || null;
}

function computeBackoffMs(out, attempt) {
  const retryAfter = Number(headerValue(out.headers, "retry-after") || headerValue(out.headers, "retryAfter") || 0);
  if (out.status === 429 && Number.isFinite(retryAfter) && retryAfter > 0) {
    return Math.min(retryAfter * 1000, 15 * 60 * 1000);
  }

  const reset = Number(headerValue(out.headers, "x-rate-limit-reset") || headerValue(out.headers, "rateLimitReset") || 0);
  if (out.status === 429 && Number.isFinite(reset) && reset > 0) {
    const waitMs = Math.max((reset - Math.floor(Date.now() / 1000)) * 1000 + 2000, 60_000);
    return Math.min(waitMs, 15 * 60 * 1000);
  }

  return Math.min(1000 * Math.pow(2, attempt), 60_000) + Math.floor(Math.random() * 1000);
}

function normalizeProxyResponse(response, text, json) {
  const status = Number(json?.status || response.status || 0);
  const headers = json?.headers || Object.fromEntries(response.headers.entries());
  const ok = Boolean(response.ok && status < 400 && json?.error !== "X_GATEWAY_RATE_LIMITED" && json?.error !== "X_GATEWAY_DAILY_LIMITED");

  return {
    ok,
    status,
    data: json?.data ?? json,
    headers,
    error: json?.error || json?.message || (response.ok ? "" : text.slice(0, 300)),
    text,
  };
}

export async function xProxyRequest(cfg, { path, method = "GET", query, body, headers } = {}) {
  const endpoint = trimSlash(cfg.COOKMYBOTS_X_ENDPOINT || "");
  const key = String(cfg.COOKMYBOTS_X_KEY || "");
  const finalPath = String(path || "");
  const finalMethod = String(method || "GET").toUpperCase();

  if (!endpoint || !key) {
    return {
      ok: false,
      status: 412,
      data: null,
      headers: {},
      error: "X_PROXY_NOT_CONFIGURED",
      text: "",
    };
  }

  if (!finalPath.startsWith("/2/")) {
    return {
      ok: false,
      status: 400,
      data: null,
      headers: {},
      error: "X_PROXY_PATH_MUST_START_WITH_/2/",
      text: "",
    };
  }

  const payload = {
    path: finalPath,
    method: finalMethod,
    query: query || undefined,
    body: finalMethod === "GET" || finalMethod === "HEAD" ? undefined : body,
    headers: headers || undefined,
  };

  let lastOut = null;

  for (let attempt = 0; attempt < 4; attempt += 1) {
    const started = Date.now();
    info("x proxy call start", {
      path: finalPath,
      method: finalMethod,
      attempt: attempt + 1,
    });

    try {
      const response = await fetch(endpoint + "/proxy", {
        method: "POST",
        headers: {
          Authorization: "Bearer " + key,
          "Content-Type": "application/json",
        },
        body: JSON.stringify(payload),
      });

      const { text, json } = await readResponse(response);
      const out = normalizeProxyResponse(response, text, json);
      lastOut = out;

      const meta = {
        path: finalPath,
        method: finalMethod,
        status: out.status,
        ms: Date.now() - started,
        rateLimitRemaining: headerValue(out.headers, "x-rate-limit-remaining") || headerValue(out.headers, "rateLimitRemaining"),
        rateLimitReset: headerValue(out.headers, "x-rate-limit-reset") || headerValue(out.headers, "rateLimitReset"),
        retryAfter: headerValue(out.headers, "retry-after") || headerValue(out.headers, "retryAfter"),
      };

      if (out.ok) {
        info("x proxy call success", meta);
        return out;
      }

      warn("x proxy call failure", {
        ...meta,
        error: out.error,
        bodySnippet: String(out.text || "").slice(0, 300),
      });

      const limited = out.status === 402 || out.status === 429 || out.error === "X_GATEWAY_RATE_LIMITED" || out.error === "X_GATEWAY_DAILY_LIMITED";
      const transient = limited || out.status >= 500 || out.status === 408;

      if (!transient || attempt === 3) return out;

      const waitMs = computeBackoffMs(out, attempt + 1);
      warn("x proxy backoff", {
        path: finalPath,
        method: finalMethod,
        status: out.status,
        waitMs,
      });
      await sleep(waitMs);
    } catch (err) {
      error("x proxy call exception", {
        path: finalPath,
        method: finalMethod,
        attempt: attempt + 1,
        error: safeErr(err),
      });

      if (attempt === 3) {
        return {
          ok: false,
          status: 0,
          data: null,
          headers: {},
          error: safeErr(err),
          text: "",
        };
      }

      await sleep(computeBackoffMs(lastOut || { status: 0, headers: {} }, attempt + 1));
    }
  }

  return lastOut || {
    ok: false,
    status: 0,
    data: null,
    headers: {},
    error: "X_PROXY_UNKNOWN_FAILURE",
    text: "",
  };
}

export function healthCheck(cfg) {
  return xProxyRequest(cfg, {
    path: "/2/users/me",
    method: "GET",
  });
}

export function searchRecent(cfg, query) {
  return xProxyRequest(cfg, {
    path: "/2/tweets/search/recent",
    method: "GET",
    query,
  });
}

export function createPost(cfg, text) {
  return xProxyRequest(cfg, {
    path: "/2/tweets",
    method: "POST",
    body: { text },
  });
}

